"""
MKT Original Language Commentary — Deuteronomy chapters 30–31
Run: python3 scripts/zc-original-deuteronomy-30-31.py

Source data used:
- data/interlinear/deuteronomy.json
- data/translation/glossary-hebrew.json
- data/translation/draft/mediating/deuteronomy.json

Key decisions in this range:
- Ch 30 v6: מוּל (mûl) = circumcise — YHWH performs circumcision of heart unilaterally; this is the NT's
  new covenant fulfillment ground (Rom 2:29; Phil 3:3)
- Ch 30 vv11-14: Paul quotes vv12-14 in Rom 10:6-8 reading the "word" christologically;
  the Deuteronomic sense (the commandment is not inaccessible) is the foundation for Paul's typological
  re-application to "the word of faith"
- שׁוּב (shûb) treated consistently throughout ch 30 as both "return/repent" (human) and "restore/turn"
  (divine) — the mirrored usage in vv2-3 is noted
- חזק ואמץ (ḥăzaq weʾĕmāṣ) in 31:6,7,23 is a fixed covenant-commissioning formula; its NT re-use
  in Heb 13:5 citing Deut 31:6/8 is noted
- 31:9 writing of Torah as textual artifact — significant for biblical literacy and public reading
- 31:19-22 the song as covenant witness — ʿēd (H5707) framework throughout
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    """Merge new_data into existing without overwriting present entries."""
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

DEUTERONOMY = {
  "30": {
    "1": '<p>The conditional opener — <strong>כִּי יָבֹאוּ עָלֶיךָ כָּל הַדְּבָרִים הָאֵלֶּה</strong> (<em>kî yābōʾû ʿālêkā kol-haddĕbārîm hāʾēlleh</em>) — "when all these things come upon you, the blessing and the curse" — assumes that both outcomes will be experienced. The construction is not a simple conditional ("if") but anticipatory ("when"). Moses does not present the curse as merely hypothetical; he projects a future that includes exile. This verse opens the covenant\'s most forward-looking section: what happens after catastrophe.</p>',
    "2": '<p><strong>וְשַׁבְתָּ</strong> (<em>wĕshavtā</em>) — "and you return": the verb <em>shûb</em> (H7725) is Deuteronomy\'s signature term for the covenant reversal that begins with the will. The phrase <em>bĕkol lĕbābĕkā ûbĕkol napšĕkā</em> (with all your heart and all your soul) echoes the Shema\'s demand-language (6:5), indicating that the return demanded is total reorientation, not grudging compliance.</p>',
    "3": '<p><strong>וְשָׁב יְהוָה אֱלֹהֶיךָ</strong> (<em>wĕshāb Yhwh ʾĕlōhêkā</em>) — "and YHWH your God will return." The same verb <em>shûb</em> used of Israel in v2 is now used of YHWH — the divine turning mirrors and responds to the human turning. This verbal mirroring is theologically significant: YHWH\'s restoration is not independent of Israel\'s repentance but neither is it merely reactive; it is the covenantal counterpart to Israel\'s return. <em>Wĕriḥămĕkā</em> ("and will have compassion on you") — the noun <em>raḥămîm</em> (H7356, from the root for "womb") indicates the most intimate form of divine tenderness.</p>',
    "4": '<p><strong>נִדַּח</strong> (<em>niddaḥ</em>, Niphal of H5080) — "driven out/banished." The passive form indicates that the scattering is not self-chosen exile but forced expulsion. The extremity of "the ends of heaven" (<em>qĕṣēh hashshāmāyim</em>) marks the reach of the divine retrieval: no geographic distance places the exiled Israelite beyond the covenant\'s reach. <em>Wĕmishshām</em> — "and from there YHWH your God will gather you."</p>',
    "5": '<p><strong>הֵיטִיב</strong> (<em>hêṭîb</em>, Hiphil of H3190) — "to do good to, benefit": the restoration covenant promises material improvement. The phrase <em>mēʾăbōtêkā</em> ("more than your fathers") introduces a superlative: the restored community will exceed in blessing what any previous generation experienced. This "better than before" motif connects forward to the new covenant vision of Jer 31 and Ezek 36.</p>',
    "6": '<p><strong>וּמָל יְהוָה אֱלֹהֶיךָ אֶת לְבָבְךָ</strong> (<em>ûmāl Yhwh ʾĕlōhêkā ʾet lĕbābĕkā</em>) — "and YHWH your God will circumcise your heart." The verb <em>mûl</em> (H4135) is the standard term for physical circumcision; applied to the heart, it describes the removal of the hardened outer covering that prevents full covenant loyalty. The decisive point is the subject: YHWH acts unilaterally. Unlike 10:16 where Israel is commanded "circumcise your heart," here YHWH performs the act himself. This is the closest Deuteronomy comes to announcing the new covenant — the heart-transformation that Jer 31:33 ("I will put my law on their heart") and Ezek 36:26 ("I will give you a new heart") will develop. Paul\'s argument in Rom 2:29 ("circumcision is a matter of the heart, by the Spirit") and Phil 3:3 draws directly on this trajectory.</p>',
    "7": '<p><strong>נָתַן</strong> (<em>nātan</em>) — "will place/put": YHWH will place (<em>yittēn</em>) the curses upon the enemies. The covenant reversal is also judicial: those who afflicted Israel under divine sanction will themselves become the objects of covenant curse. This is the juridical dimension of restoration — not merely rescue but vindication.</p>',
    "8": '<p><strong>וְאַתָּה תָשׁוּב</strong> (<em>wĕʾattāh tāshûb</em>) — "and you will return": the initial condition of v2 is now restated as a future certainty, not a hypothesis. The shift from conditional to indicative reflects the structure of grace: YHWH\'s prior action (v6, circumcision of heart) makes the human return possible and certain. <em>Shāmaʿtā bĕqôl Yhwh</em> — "you will obey the voice of YHWH" — the obedience follows from the heart-transformation, not the reverse.</p>',
    "9": '<p><strong>יוֹתִירְךָ</strong> (<em>yôtîrĕkā</em>, Hiphil of H3498) — "will make you overflow/abound": the prosperity language echoes the blessing catalog of ch 28, but now in the register of restoration rather than initial covenant-entry. The three spheres of blessing — womb, animal stock, ground — are the fundamental productive capacities of agrarian life. <em>Kî yāshûb Yhwh lāśôś ʿālêkā lĕṭôb kaʾăsher śās ʿal ʾăbōtêkā</em>: "as he rejoiced over your fathers" — YHWH rejoices (<em>śôś</em>) over the restored people, not merely restoring a legal status but expressing divine delight.</p>',
    "10": '<p><strong>בְּשׁוּבְךָ</strong> (<em>bĕshûbĕkā</em>) — "when you return": the absolute form of the condition — with all your heart (<em>lēbāb</em>) and all your soul (<em>nepeš</em>) — recapitulates the Shema\'s demand. The restoration covenant is not a lowering of the standard; it is the same total-person covenant loyalty, now made possible by the circumcision of v6. <em>Bĕkol lĕbābĕkā ûbĕkol napšĕkā</em> here serves as the closing bracket of the section that opened at v2 with the same phrase.</p>',
    "11": '<p><strong>לֹא נִפְלֵאת</strong> (<em>lōʾ niphlĕʾt</em>, Niphal of H6381) — "not too wonderful/extraordinary." The root <em>plʾ</em> means extraordinary, beyond ordinary capacity — used of divine wonders (Exod 3:20) and things too great for human comprehension. The denial — "this commandment is not too extraordinary for you, not too far away" — counters the defeatist assumption that covenant faithfulness requires superhuman capacity. The NT picks this up; Paul quotes vv12-14 in Rom 10:6-8 to argue that Christ is not inaccessibly remote.</p>',
    "12": '<p><strong>לֹא בַשָּׁמַיִם הִוא</strong> (<em>lōʾ bāshāmayim hîʾ</em>) — "not in heaven is it." The rhetorical question "who will go up to heaven for us and get it for us?" frames the alternative as an impossibility — no one is capable of the ascent required. In its Deuteronomic context, this means: the Torah does not require superhuman effort; it has been given accessibly. Paul re-reads the rhetorical question in Rom 10:6-8: "who will ascend into heaven?" (= to bring Christ down) and "who will descend into the abyss?" (= to bring Christ up from the dead) — he applies the Deuteronomic impossibility-argument typologically to show that faith does not require impossible acts because Christ has already accomplished the ascent and descent.</p>',
    "13": '<p><strong>מֵעֵבֶר לַיָּם</strong> (<em>mēʿēber layyām</em>) — "beyond the sea." The paired impossibilities — heaven (v12) and sea (v13) — represent the two axes of inaccessibility in ancient cosmology: vertical and horizontal. The sea (<em>yām</em>) often carries the connotation of the deep and chaotic in Hebrew cosmology. Paul reads this as "the abyss" (<em>ābyssos</em>) in his re-application (Rom 10:7). The point in both contexts is the same: the saving word is not inaccessible by cosmic distance.</p>',
    "14": '<p><strong>כִּי קָרוֹב אֵלֶיךָ הַדָּבָר מְאֹד</strong> (<em>kî qārôb ʾēlêkā haddābār mĕʾōd</em>) — "but the word is very near to you." <em>Qārôb</em> (H7138, near, close) is the climactic reversal of the two impossibility-scenarios. The three locations — mouth (<em>bĕpîkā</em>), heart (<em>bĕlibĕkā</em>), and the stated purpose "to do it" (<em>laʿăśôtô</em>) — describe a word that has already been internalized and is ready for enactment. The triad implies: oral recitation (in your mouth), inner comprehension (in your heart), and active obedience (to do it). Paul quotes this verse as the starting point for his argument that "the word of faith" (the gospel) is equally accessible — the Torah\'s claim for the nearness of the covenant word becomes the gospel\'s claim for the nearness of Christ.</p>',
    "15": '<p><strong>הַחַיִּים וְהַטּוֹב</strong> (<em>haḥayyîm wĕhaṭṭôb</em>) — "life and good": the two positive covenant outcomes are placed first in the pairings. The contrast is with <em>hāmāwet wĕhārāʿ</em> (death and evil). The fourfold pairing — life/death and good/evil — makes explicit the moral polarity implicit in the covenant from the beginning. Deuteronomy\'s ethics are not situational: life is the path of covenant obedience; death is the path of disobedience. The simplicity is intentional; the cosmic stakes are not to be minimized.</p>',
    "16": '<p><strong>לְאַהֲבָה אֶת יְהוָה</strong> (<em>lĕʾahăbāh ʾet Yhwh</em>) — "to love YHWH": the imperative returns to the ground-level command. Obedience and love are not presented as alternatives; the verb <em>ʾāhab</em> in covenant context is the encompassing term for covenantal loyalty-in-action. The three-fold structure — love YHWH, walk in his ways, keep his commandments — recapitulates the Shema\'s demand in its fullest form. The result: blessing and multiplication in the land.</p>',
    "17": '<p><strong>יִפְנֶה לְבָבְךָ</strong> (<em>yipneh lĕbābĕkā</em>) — "if your heart turns away": the verb <em>pānāh</em> (H6437) here has the sense of deflection — the heart that was to be wholly toward YHWH (6:5) turning to face something else. The consequence — serving other gods — follows naturally; the heart\'s orientation determines the object of worship. The "turning" of the heart is the internal act that precedes all external apostasy.</p>',
    "18": '<p><strong>אָבֹד תֹּאבֵדוּן</strong> (<em>ābōd tōʾbēdûn</em>) — infinitive absolute intensifying the finite verb: "you will certainly/utterly perish." The intensified form marks the severity; this is not a vague threat but a covenantal certainty. <em>Lōʾ taʾărîkûn yāmîm ʿal hāʾădāmāh</em> — "you will not prolong your days on the land": longevity in the land, promised for obedience (5:16; 6:2), is here reversed as the sanction for covenant defection.</p>',
    "19": '<p><strong>הַעִידֹתִי בָכֶם הַיּוֹם אֶת הַשָּׁמַיִם וְאֶת הָאָרֶץ</strong> (<em>haʿîdōtî bākem hayyôm ʾet hashshāmayim wĕʾet hāʾāreṣ</em>) — "I call to witness against you today heaven and earth." The formal invocation of cosmic witnesses is the standard closing of a vassal-treaty — the suzerain calls on the divine witnesses to guarantee the covenant terms. Since YHWH himself is the suzerain, the witnesses are the impersonal creation: heaven and earth. The formal verb <em>ʿûd</em> (H5749, Hiphil: to bear witness/testify against) gives this a legal register: Moses is making a formal treaty-deposition. <em>Habĕḥer baḥayyîm lĕmaʿan tiḥyeh</em> — "choose life so that you may live" — the imperative plus result clause is the clearest single statement of Deuteronomy\'s entire argument.</p>',
    "20": '<p><strong>לְאַהֲבָה אֶת יְהוָה אֱלֹהֶיךָ</strong> (<em>lĕʾahăbāh ʾet Yhwh ʾĕlōhêkā</em>) — "to love YHWH your God": the closing verse of the section recapitulates its three-term structure: love (<em>ʾāhab</em>), obey (<em>shāmaʿ bĕqôlô</em>), hold fast (<em>dābaq bô</em>, H1692 — to cling to, as the vine to the trellis, as husband and wife, Gen 2:24). <strong>כִּי הוּא חַיֶּיךָ</strong> (<em>kî hûʾ ḥayyêkā</em>) — "for he is your life": the capstone of the whole ethical argument. YHWH is not merely the source of life as a secondary cause; he is constitutively Israel\'s life. Obedience is not the mechanism for securing life from YHWH; it is the way of inhabiting the life that is already YHWH himself.</p>'
  },
  "31": {
    "1": '<p>The opening <strong>וַיֵּלֶךְ מֹשֶׁה</strong> (<em>wayyēlek mōsheh</em>) — "and Moses went" — is slightly unusual; some ancient versions read "and Moses finished speaking." The MT as it stands emphasizes physical movement — Moses departs one context (the parenetic discourse) to enter another (the formal transition). Chapter 31 is the climax of the Mosaic career: the writing, transmission, and cosmic witnessing of the Torah.</p>',
    "2": '<p><strong>בֶּן מֵאָה וְעֶשְׂרִים שָׁנָה אָנֹכִי</strong> (<em>ben meʾāh wĕʿeśrîm shānāh ʾānōkî</em>) — "I am one hundred and twenty years old." One hundred and twenty is a round number in Israel\'s numerical symbolism; it also happens to divide into three periods of 40 (Egypt, wilderness before Horeb, wilderness after Horeb). <em>Lōʾ ʾûkal ʿôd lāṣēʾt wĕlābōʾ</em> — "I am no longer able to go out and come in": the idiom for military leadership and active governance. The incapacity is presented first as physical/functional before the divine prohibition (<em>Yhwh ʾāmar ʾēlay lōʾ taʿăbōr ʾet hayyardēn</em>) is added as the definitive reason.</p>',
    "3": '<p><strong>יְהוָה אֱלֹהֶיךָ הוּא עֹבֵר לְפָנֶיךָ</strong> (<em>Yhwh ʾĕlōhêkā hûʾ ʿōbēr lĕpānêkā</em>) — "YHWH your God himself is crossing over before you." The emphatic pronoun <em>hûʾ</em> (he himself) places the stress on divine agency: the conquest is YHWH\'s crossing, not merely Israel\'s. <em>Hûʾ yashḥît ʾet haggôyim hāʾēlleh</em> — "he will destroy these nations before you": the divine warrior motif frames the entire conquest as YHWH\'s military campaign in which Israel participates. Joshua (<em>yĕhôshûaʿ</em>) is named as the human instrument but under YHWH\'s leadership.</p>',
    "4": '<p><strong>כַּאֲשֶׁר עָשָׂה לְסִיחֹן וּלְעוֹג</strong> (<em>kaʾăsher ʿāśāh lĕSîḥōn ûlĕʿÔg</em>) — "as he did to Sihon and Og." The Transjordanian victories function as proof-of-concept throughout Deuteronomy: YHWH has already defeated two powerful Amorite kings; the conquest of Canaan will extend the same pattern. The argument is analogical: from prior demonstration to present expectation.</p>',
    "5": '<p>The command "do to them according to all the commandment I have commanded you" (<em>kaḵol hammiṣwāh ʾăsher ṣiwwîtî ʾetkem</em>) situates the military action within the covenant framework — this is not arbitrary violence but a commanded action with its own Torah-regulated form. The <em>ḥērem</em> of ch 7 governs the expected conduct.</p>',
    "6": '<p><strong>חִזְקוּ וְאִמְצוּ</strong> (<em>ḥizqû wĕʾimṣû</em>) — "be strong and courageous." This is the covenant-commissioning formula that will define Joshua\'s leadership throughout the subsequent narrative (31:7, 23; Josh 1:6, 7, 9, 18). <em>Ḥāzaq</em> (H2388) = firm, strong — military fortitude; <em>ʾāmaṣ</em> (H553) = resolute, bold — the inner determination that fortitude requires. Together they form a hendiadys for unshakeable covenantal resolve. The ground for the command — <em>lōʾ tîrĕʾû wĕlōʾ taḥpĕṣû mippĕnêhem</em> ("do not be afraid or in dread of them") — is YHWH\'s presence: <em>kî Yhwh ʾĕlōhêkā hûʾ hahōlēk ʿimmāk lōʾ yarpĕkā wĕlōʾ yaʿazbekkā</em> ("for YHWH your God himself goes with you; he will not relax his hold on you or forsake you").</p>',
    "7": '<p>Moses\'s words to Joshua are spoken <em>lĕʿênê kol-yiśrāʾēl</em> (before the eyes of all Israel) — the public commissioning is a covenantal transfer, not merely a private appointment. The double formula <em>ḥăzaq weʾĕmāṣ</em> is repeated; its repetition emphasizes that the whole command-structure of Israel\'s future passes through Joshua\'s resolve.</p>',
    "8": '<p><strong>לֹא יַרְפְּךָ וְלֹא יַעַזְבֶךָּ</strong> (<em>lōʾ yarpĕkā wĕlōʾ yaʿazbekkā</em>) — "he will not relax his hold on you and will not forsake you." Two distinct verbs: <em>rāpāh</em> (H7503) means to relax, let go, slacken — the image of a hand loosening its grip; <em>ʿāzab</em> (H5800) means to abandon, forsake completely. Together they form a comprehensive negative: YHWH will neither loosen his hold nor walk away. Heb 13:5 quotes this verse (via LXX: <em>ou mē se anō, oude ou mē se enkatalipō</em>) as the ground for Christian contentment — the same covenant-assurance given to Joshua is applied to believers whose God is the same.</p>',
    "9": '<p><strong>וַיִּכְתֹּב מֹשֶׁה</strong> (<em>wayyiktōb mōsheh</em>) — "and Moses wrote": the writing (<em>kāṯab</em>, H3789) of the Torah is a formal act in the transition narrative. The Torah becomes a written artifact — not merely an oral tradition but a text that can be entrusted to others. The recipients are the Levitical priests (<em>hakkōhănîm bĕnê lēwî</em>) who carry the ark (<em>hāʾārôn bĕrît Yhwh</em>) and "all the elders of Israel" — the dual custodians of the covenant text represent both sacred/priestly and civic/elder authority structures.</p>',
    "10": '<p><strong>מִקֵּץ שֶׁבַע שָׁנִים</strong> (<em>miqqēṣ shebaʿ shānîm</em>) — "at the end of seven years": the septennial reading cycle aligns with the Sabbatical Year (<em>shĕmiṭṭāh</em>, ch 15), which itself rests on the seven-day Sabbath pattern. The recurrence guarantees that no generation of Israelites will grow up without public Torah instruction. <em>Bĕmôʿēd shĕnat hashshĕmiṭṭāh bĕḥag hasukkôt</em> — at the Feast of Tabernacles — the covenant renewal ceremony is embedded in the liturgical calendar\'s harvest celebration.</p>',
    "11": '<p><strong>בְּבוֹא כָל יִשְׂרָאֵל</strong> (<em>bĕbôʾ kol yiśrāʾēl</em>) — "when all Israel comes." The verb <em>bôʾ</em> here carries the technical sense of pilgrimage-appearance before YHWH (as in Exod 23:17, where Israel "appears" before YHWH at the three festivals). The reading occurs <em>lĕʾoznêhem</em> ("in their ears") — not silently but as public oral proclamation. Torah is constituted by being heard communally, not merely possessed textually.</p>',
    "12": '<p><strong>הַקְהֵל אֶת הָעָם</strong> (<em>haqhēl ʾet hāʿām</em>) — "assemble the people": the Hiphil imperative of <em>qāhal</em> (H6950) — to convene the assembly (<em>qāhāl</em>). The list that follows — men, women, children (<em>haṭṭap</em>, the little ones), and the sojourner (<em>gēr</em>) — is the comprehensive covenant community. No social category is excluded from the hearing. The purpose: <em>lĕmaʿan yishĕmĕʿû ûlĕmaʿan yilmĕdû wĕyārĕʾû</em> — "so that they may hear, learn, and fear." The sequence is instructional: hearing precedes learning; learning produces the fear-of-YHWH that is the goal of Torah.</p>',
    "13": '<p><strong>וּבְנֵיהֶם אֲשֶׁר לֹא יָדְעוּ</strong> (<em>ûbĕnêhem ʾăsher lōʾ yādĕʿû</em>) — "and their children who have not known": the explicit concern for the generation that has not yet encountered the covenant text establishes intergenerational education as a covenantal obligation. The child who "does not know" (<em>lōʾ yādaʿ</em>) is not ignorant of all things but specifically lacks the formational encounter with Torah that constitutes covenant identity. The septennial reading ensures each new generation receives the foundational text.</p>',
    "14": '<p><strong>קָרַב יְמֵי מֹשֶׁה לָמוּת</strong> (<em>qārab yĕmê mōsheh lāmût</em>) — "the days of Moses have drawn near to die." The same verb <em>qārab</em> (H7126, to draw near, approach) used in ceremonial contexts of approaching the sanctuary. Moses\'s death approaches in the language of a sacred threshold. <em>Môʿēd</em> (H4150, tent of meeting) — YHWH\'s summons to the tent marks the transition as divinely orchestrated: this is not merely biological death but covenantal completion.</p>',
    "15": '<p><strong>בְּעַמּוּד עָנָן</strong> (<em>bĕʿammûd ʿānān</em>) — "in a pillar of cloud": the theophanic sign that marked YHWH\'s guidance through the wilderness (Exod 13:21-22; 14:19; Num 14:14). The cloud\'s standing over the door of the tent (<em>ʿal petaḥ hāʾōhel</em>) is a formal divine arrival — YHWH\'s presence in a visible but veiled form. The occasion is the formal commissioning of Joshua, requiring direct divine presence as the authorizing act.</p>',
    "16": '<p>YHWH\'s announcement of future apostasy — <strong>זֹנֶה אַחֲרֵי אֱלֹהֵי נֵכַר הָאָרֶץ</strong> (<em>zōneh ʾaḥărê ʾĕlōhê nēkar hāʾāreṣ</em>) — uses the verb <em>zānāh</em> (H2181, to prostitute, commit adultery/harlotry) for apostasy, the same metaphor the prophets will develop at length (Hosea, Jeremiah, Ezekiel). The people\'s covenant relationship with YHWH is marital; going after foreign gods is an act of marital betrayal. The divine foreknowledge is not fatalistic predetermination but prophetic realism about the heart\'s inclination without divine transformation (see 30:6).</p>',
    "17": '<p><strong>חָרָה אַפִּי</strong> (<em>ḥārāh ʾappî</em>) — "my anger will burn": the idiom of divine anger as heat — <em>ḥārāh</em> (H2734) from the root of burning/glowing. The consequence is <strong>הִסְתַּרְתִּי פָנַי מֵהֶם</strong> (<em>histartî pānay mēhem</em>) — "I will hide my face from them": the concealment of the divine face is the most severe form of divine absence — not the active curse but the withdrawal of the sustaining presence that makes life possible. <em>Wĕhāyāh lĕʾekōl</em> ("and will become food for devouring") — when the divine presence is withdrawn, the covenant protections go with it.</p>',
    "18": '<p><strong>וְאָנֹכִי הַסְתֵּר אַסְתִּיר פָּנַי</strong> (<em>wĕʾānōkî hastēr ʾastîr pānay</em>) — the infinitive absolute with finite verb: "I will surely/completely hide my face." The doubled form of <em>sātar</em> (H5641, to hide, conceal) intensifies beyond v17\'s past-tense report to a present-tense guarantee. The pronoun <em>ʾānōkî</em> (I myself) is emphatic. <em>Bĕkol hārāʿāh ʾăsher ʿāśāh kî pānāh ʾel ʾĕlōhîm ʾăḥērîm</em> — "because of all the evil they have done in turning to other gods." The covenant logic is strict: turning away from YHWH results in YHWH\'s own turning away.</p>',
    "19": '<p><strong>כִּתְבוּ לָכֶם אֶת הַשִּׁירָה הַזֹּאת</strong> (<em>kitbû lākem ʾet hashshîrāh hazzōʾt</em>) — "write for yourselves this song." The Song of Moses (ch 32) is commanded as a written text — its being-written is itself a covenantal act. The purpose: <em>lĕmaʿan tihyeh-lî hashshîrāh hazzōʾt lĕʿēd bibĕnê yiśrāʾēl</em> — "so that this song may be a witness (<em>ʿēd</em>, H5707) for me against the children of Israel." Torah is also given as a <em>ʿēd</em>-text (v26); the Song doubles the witness-function of the written word. Both testify to the people\'s covenant obligation and to YHWH\'s faithfulness and righteousness when judgment comes.</p>',
    "20": '<p><strong>שָׁמֵן וְשָׂבֵעַ</strong> (<em>shāmēn wĕsābēaʿ</em>) — "fat and full": the Deuteronomic prosperity trap stated with characteristic directness — abundance produces the contempt that breaks the covenant. <em>Wĕpānāh ʾel ʾĕlōhîm ʾăḥērîm</em> — "and will turn to other gods": the same verb <em>pānāh</em> (H6437) used of the heart turning away in 30:17. Physical satiation turns the heart from its proper object. The Song will remain as a standing indictment even when the people forget the Law.</p>',
    "21": '<p><strong>כִּי לֹא תִשָּׁכַח מִפִּי זַרְעוֹ</strong> (<em>kî lōʾ tishshākaḥ mippî zarʿô</em>) — "for it will not be forgotten from the mouths of his offspring": the Song\'s permanence is the ground of its witness-function. While the written law might be lost or ignored, the Song is oral — it lives in the mouth and passes down through recitation. The two witness-structures (written Torah + oral Song) are complementary: Israel may neglect one but the other persists. <em>Kî yādaʿtî ʾet yiṣrô</em> — "for I know their inclination": the divine knowledge of the fallen inclination (<em>yēṣer</em>, H3336 — the formed thing, the bent of the will) grounds the need for the witness-structure.</p>',
    "22": '<p><strong>וַיִּכְתֹּב מֹשֶׁה</strong> (<em>wayyiktōb mōsheh</em>) — "and Moses wrote": the execution of the divine command of v19. Moses writes the Song "that day" (<em>bayyôm hahûʾ</em>) — the immediacy of obedience is a mark of the faithful mediator. The Song\'s writing is Moses\'s last recorded act of writing before his death.</p>',
    "23": '<p><strong>וַיְצַו אֶת יְהוֹשֻׁעַ</strong> (<em>wayĕṣaw ʾet yĕhôshûaʿ</em>) — YHWH commissions Joshua directly, not through Moses. The subject is YHWH (note the context: YHWH appeared in the pillar of cloud at v15). The formula <em>ḥăzaq weʾĕmāṣ</em> is now spoken by YHWH himself — the same formula Moses used in 31:6 and 31:7. The divine repetition of the commissioning formula gives it ultimate authority: Joshua\'s strength-and-courage is not a merely human charge but a divine mandate. <em>Kî ʾattāh tābîʾ ʾet bĕnê yiśrāʾēl ʾel hāʾāreṣ</em> — "for you will bring the children of Israel into the land": the divine certainty of the conquest is built into the commission.</p>',
    "24": '<p><strong>כְּכַלּוֹת מֹשֶׁה לִכְתֹּב</strong> (<em>kĕkallôt mōsheh liktōb</em>) — "when Moses finished writing": <em>kāllāh</em> (H3615) marks the completion as total — not a draft but the finished artifact. The scope — <em>ʾet dibĕrê hattôrāh hazzōʾt ʿal sēper ʿad tummām</em> ("the words of this Torah on a scroll, to their completion") — emphasizes the exhaustiveness of the written deposit. Torah is a completed, bounded text, not an open-ended accumulation.</p>',
    "25": '<p><strong>הַלְּוִיִּם נֹשְׂאֵי אֲרוֹן בְּרִית יְהוָה</strong> (<em>hallĕwiyyîm nōśĕʾê ʾărôn bĕrît Yhwh</em>) — "the Levites who carried the ark of the covenant of YHWH": the ark-carriers are the proper recipients of the Torah scroll. The ark of the covenant (<em>ʾărôn habbĕrît</em>) is the covenant container — it houses the stone tablets; now the Torah scroll is added alongside it. The Levites\' role as carrier-priests makes them the covenant custodians in a dual sense: they carry the container of the original Ten Words and now also the full written Torah.</p>',
    "26": '<p><strong>לָקֹחַ אֵת סֵפֶר הַתּוֹרָה הַזֶּה</strong> (<em>lāqōaḥ ʾēt sēper hattôrāh hazzeh</em>) — "take this book of the Torah." The Torah is designated <em>sēper</em> (H5612, scroll/document) — a physical, portable object. Its placement <em>bĕṣad ʾărôn bĕrît Yhwh</em> ("at the side of the ark of the covenant of YHWH") — not inside but alongside — distinguishes it from the stone tablets while giving it covenantal proximity. The stated purpose: <em>wĕhāyāh shām bĕkā lĕʿēd</em> — "and it shall be there in you as a witness." The Torah as witness (<em>ʿēd</em>) against Israel mirrors the Song as witness (v19); the two together form the covenant\'s double-witness structure (requiring two witnesses for legal testimony, Deut 17:6).</p>',
    "27": '<p><strong>כִּי אָנֹכִי יָדַעְתִּי אֶת מֶרְיְךָ</strong> (<em>kî ʾānōkî yādaʿtî ʾet meryĕkā</em>) — "for I myself know your rebellion." <em>Mĕrî</em> (H4805, rebellion) is a strong term — not merely disobedience but defiant resistance. Moses grounds the need for the double-witness structure (Torah scroll + Song) in his own experiential knowledge of Israel\'s character: <em>ʿorpĕkem qĕshê hûʾ</em> — "you are stiff-necked" (literally: your neck is hard). The <em>ʿōrep</em> (H6203, nape of the neck) is the part that stiffens when refusing to bow or yield; the idiom captures the posture of the defiant subject before the sovereign.</p>',
    "28": '<p><strong>הַקְהִילוּ אֵלַי אֶת כָּל זִקְנֵי שִׁבְטֵיכֶם</strong> (<em>haqhîlû ʾēlay ʾet kol ziqnê shivṭêkem</em>) — "assemble before me all the elders of your tribes." The formal assembly (<em>qāhal</em>) of elders and officers (<em>shōṭĕrêkem</em>) constitutes the covenant-legal body that can receive the formal witness-declaration. <em>Wĕʾaʿîdāh bām ʾēt hashshāmayim wĕʾet hāʾāreṣ</em> — "and I will cause heaven and earth to witness against them": the same cosmic-witness invocation of 30:19, now formally invoked at the covenant\'s close.</p>',
    "29": '<p><strong>כִּי יָדַעְתִּי</strong> (<em>kî yādaʿtî</em>) — "for I know": the prophetic-certainty formula. Moses does not merely suspect future apostasy; he declares it as foreknown. <em>Maḥărê môtî hashḥēt tashḥîtûn</em> ("after my death you will surely corrupt yourselves") — the infinitive absolute <em>hashḥēt tashḥîtûn</em> intensifies: "certainly corrupt, utterly go to ruin." <em>Wĕqārāʾt ʾetkem hārāʿāh bĕʾaḥărît hayyāmîm</em> — "and evil will befall you in the latter days": the phrase <em>ʾaḥărît hayyāmîm</em> (H319 + H3117) — "latter days/end of days" — carries eschatological weight throughout the prophets (Isa 2:2; Jer 23:20; Ezek 38:16; Dan 10:14). Moses\'s farewell points not just to the next generation\'s apostasy but to the full arc of Israel\'s covenantal history.</p>',
    "30": '<p><strong>וַיְדַבֵּר מֹשֶׁה בְּאָזְנֵי כָּל קְהַל יִשְׂרָאֵל</strong> (<em>wayĕdabbēr mōsheh bĕʾoznê kol qĕhal yiśrāʾēl</em>) — "and Moses spoke in the ears of all the assembly of Israel." The phrase <em>bĕʾoznê</em> (in the ears of) is the oral-proclamation formula: Torah and Song are not privately transmitted but publicly auditioned. <em>Kol qĕhal yiśrāʾēl</em> — the full assembly as recipient of the Song — closes the narrative-frame of ch 31 and opens the Song of Moses (ch 32), the final and most sustained piece of Mosaic poetry in the Pentateuch.</p>'
  }
}

def main():
    existing = load_comm('mkt-original', 'deuteronomy')
    merge_comm(existing, DEUTERONOMY)
    save_comm('mkt-original', 'deuteronomy', existing)
    print('Deuteronomy 30-31 mkt-original written.')

if __name__ == '__main__':
    main()
